using System;
using System.Diagnostics;
using System.IO;

public static void GeneratePdfFromHtml(string htmlFilePath, string pdfFilePath, PdfOptions options)
{
    // Prevent command injection by validating the input parameters
    if (htmlFilePath == null || !File.Exists(htmlFilePath))
        throw new ArgumentException("Invalid HTML file path", nameof(htmlFilePath));

    if (pdfFilePath == null)
        throw new ArgumentNullException(nameof(pdfFilePath));

    // Build the wkhtmltopdf command and execute it
    string command = $"wkhtmltopdf --page-size {options.PageSize} --orientation {options.Orientation} \"{htmlFilePath}\" \"{pdfFilePath}\"";
    ProcessStartInfo startInfo = new ProcessStartInfo("cmd", "/c " + command);
    startInfo.UseShellExecute = false;
    startInfo.RedirectStandardOutput = true;
    startInfo.CreateNoWindow = true;
    using (Process process = Process.Start(startInfo))
    {
        process.WaitForExit();
        if (process.ExitCode != 0)
            throw new Exception("Error generating PDF");
    }
}